  // Try to extract JSON from the output — Claude sometimes wraps it in prose or code fences
  let cleaned = agentOutput;

  // Remove code fences
  cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

  // If it doesn't start with {, try to find JSON object in the text
  if (!cleaned.startsWith('{')) {
    const jsonMatch = cleaned.match(/\{[\s\S]*"blocks"[\s\S]*\}/);
    if (jsonMatch) {
      cleaned = jsonMatch[0];
    }
  }

  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: split raw output into chunks that fit Slack's 3000 char limit per block
  const maxLen = 2900;
  const text = agentOutput || 'Briefing generation failed.';
  const chunks = [];
  for (let i = 0; i < text.length; i += maxLen) {
    chunks.push(text.slice(i, i + maxLen));
  }

  const blocks = chunks.map((chunk, idx) => ({
    type: "section",
    text: { type: "mrkdwn", text: idx === 0 ? chunk : '...' + chunk }
  }));

  parsed = {
    notification_text: "Your briefing is ready",
    blocks
  };
}

// Enforce Slack limits
if (parsed.blocks) {
  parsed.blocks = parsed.blocks.map(block => {
    // Max 10 fields per section
    if (block.fields && block.fields.length > 10) {
      block.fields = block.fields.slice(0, 10);
    }
    // Max 3000 chars per text field in section blocks
    if (block.text && block.text.text && block.text.text.length > 3000) {
      block.text.text = block.text.text.slice(0, 2997) + '...';
    }
    // Max 3000 chars per field text
    if (block.fields) {
      block.fields = block.fields.map(f => {
        if (f.text && f.text.length > 2000) {
          f.text = f.text.slice(0, 1997) + '...';
        }
        return f;
      });
    }
    return block;
  });
  // Max 50 blocks
  if (parsed.blocks.length > 50) {
    parsed.blocks = parsed.blocks.slice(0, 50);
  }
}

return [{
  json: {
    notificationText: parsed.notification_text || "Your briefing",
    blocks: JSON.stringify(parsed.blocks),
